package day3TypesofOperators;

public class AssignmentOperators {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		int a=20;
		a+=40;
		System.out.println(a);
		
		a-=40;
		System.out.println(a);

        a*=40;
		System.out.println(a);
		
		a/=40;
		System.out.println(a);
		
		a%=40;
		System.out.println(a);
		
		
	}

}
